import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface RatingDistribution {
  rating: number;
  count: number;
}

interface ProductData {
  product: {
    name: string;
    averageRating: number;
    reviewCount: number;
  };
  ratingDistribution: RatingDistribution[];
}

export default function Widget() {
  const productData = response.data as ProductData;
  const clipPathId = React.useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              {productData.product.name}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Average Rating: {productData.product.averageRating} ({productData.product.reviewCount} reviews)
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: productData.ratingDistribution.map(r => r.count),
                  color: response.meta.primaryColor,
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: productData.ratingDistribution.map(r => r.rating.toString()),
                  id: 'ratings',
                },
              ]}
              yAxis={[{ id: 'counts' }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="ratings"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="counts"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
            </ResponsiveChartContainer>
          </Box>

          <Grid container spacing={1}>
            {productData.ratingDistribution.map((ratingDist) => (
              <Grid item xs={6} key={ratingDist.rating}>
                <Stack direction="row" spacing={1} alignItems="center">
                  <Typography variant="body2" sx={{ fontWeight: 600 }}>
                    {ratingDist.rating} Star
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    {ratingDist.count} reviews
                  </Typography>
                </Stack>
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
